from dataclasses import dataclass, field
from typing import List, Optional
from enum import Enum
from datetime import date

class ActionItemStatus(Enum):
    ON_TRACK   = "on_track"
    AT_RISK    = "at_risk"      # due date within 7d and not done
    OVERDUE    = "overdue"
    DONE       = "done"
    BLOCKED    = "blocked"      # needs decision to unblock

@dataclass
class ReliabilityActionItem:
    title: str
    owner: str
    due_date: date
    status: ActionItemStatus
    blocker: Optional[str] = None   # set if status == BLOCKED
    jira_id: str = ""

    @property
    def needs_escalation(self) -> bool:
        return self.status in (ActionItemStatus.OVERDUE, ActionItemStatus.BLOCKED)

    def status_line(self) -> str:
        flag = " [ESCALATE]" if self.needs_escalation else ""
        blocked_str = f" BLOCKER: {self.blocker}" if self.blocker else ""
        return (
            f"[{self.status.name}] {self.title} | {self.owner} | due {self.due_date}"
            f"{blocked_str}{flag}"
        )


def open_ai_status_block(items: List[ReliabilityActionItem]) -> str:
    lines = ["=== Prior Action Items ==="]
    done = [i for i in items if i.status == ActionItemStatus.DONE]
    open_items = [i for i in items if i.status != ActionItemStatus.DONE]
    lines.append(f"Done: {len(done)}/{len(items)}")
    lines.append("")
    for item in open_items:
        lines.append(item.status_line())
    escalate = [i for i in open_items if i.needs_escalation]
    if escalate:
        lines.append("")
        lines.append(f"DECISION NEEDED ({len(escalate)} items):")
        for i in escalate:
            lines.append(f"  {i.title}: {i.blocker or 'overdue, no update'}")
    return "\n".join(lines)

from dataclasses import dataclass
from typing import List, Optional

@dataclass
class SLOStatus:
    name: str
    target_pct: float           # e.g. 99.9
    actual_30d_pct: float
    error_budget_pct: float     # fraction of budget remaining (0-1)
    burn_rate_7d: float         # 7-day burn rate
    burn_rate_1d: float         # 1-day burn rate (for fast burns)
    top_budget_burn_events: List[str]  # incident IDs or change IDs

    @property
    def budget_pct_remaining(self) -> float:
        return self.error_budget_pct * 100

    @property
    def alert_level(self) -> str:
        if self.burn_rate_1d > 14.4 or self.error_budget_pct < 0.05:
            return "CRITICAL"   # fast-burn alert equivalent
        if self.burn_rate_7d > 5.0 or self.error_budget_pct < 0.20:
            return "WARNING"
        return "OK"

    def review_summary(self) -> str:
        return (
            f"[{self.alert_level}] {self.name}: "
            f"{self.actual_30d_pct:.3f}% (target {self.target_pct}%) | "
            f"budget remaining: {self.budget_pct_remaining:.0f}% | "
            f"burn rate 7d={self.burn_rate_7d:.1f}x, 1d={self.burn_rate_1d:.1f}x"
        )


# GenAI-specific SLOs that standard SRE reviews may not include
GENAI_SLO_DEFINITIONS = [
    "inference_availability_99_9",
    "p99_latency_under_3s_95pct",
    "safety_classifier_uptime_99_95",
    "provider_fallback_rate_under_2pct",   # % of requests requiring fallback
    "rag_retrieval_success_99pct",
    "model_version_consistency",           # DR region matches prod within 24h
]


def compute_error_budget_policy(slo: SLOStatus, days_left_in_window: int) -> str:
    """
    Returns the recommended error budget policy given current state.
    Called when alert_level is WARNING or CRITICAL.
    """
    if slo.alert_level == "CRITICAL":
        return (
            f"FREEZE: halt new feature deployments to {slo.name} path. "
            f"Require SRE sign-off for any production change. "
            f"Schedule reliability sprint for next 2 weeks."
        )
    if slo.alert_level == "WARNING" and days_left_in_window <= 10:
        return (
            f"RESTRICT: new features require SRE review. "
            f"Prioritize toil reduction and reliability fixes this sprint. "
            f"Daily burn rate check until end of window."
        )
    return "MONITOR: no policy change needed, maintain weekly burn rate check."

from dataclasses import dataclass, field
from typing import List
from datetime import date

@dataclass
class IncidentSummary:
    incident_id: str
    severity: str
    title: str
    date_opened: date
    mttr_minutes: int
    root_cause_category: str
    was_repeat: bool            # same root cause seen before
    prior_incident_id: str = "" # set if was_repeat

@dataclass
class MonthlyIncidentReport:
    month_label: str
    incidents: List[IncidentSummary]
    on_call_toil_hours: float
    sre_capacity_hours: float   # total working hours of on-call rotation

    @property
    def p1_count(self) -> int:
        return sum(1 for i in self.incidents if i.severity == "P1")

    @property
    def p2_count(self) -> int:
        return sum(1 for i in self.incidents if i.severity == "P2")

    @property
    def repeat_count(self) -> int:
        return sum(1 for i in self.incidents if i.was_repeat)

    @property
    def avg_mttr_minutes(self) -> float:
        p1s = [i for i in self.incidents if i.severity == "P1"]
        return sum(i.mttr_minutes for i in p1s) / max(1, len(p1s))

    @property
    def toil_pct(self) -> float:
        return (self.on_call_toil_hours / self.sre_capacity_hours) * 100

    def review_flags(self) -> List[str]:
        flags = []
        if self.p1_count >= 3:
            flags.append(f"P1 count {self.p1_count} >= 3: escalate to Director")
        if self.avg_mttr_minutes > 45:
            flags.append(f"MTTR {self.avg_mttr_minutes:.0f}min > 45min target: review runbooks")
        if self.repeat_count >= 2:
            flags.append(f"{self.repeat_count} repeat incidents: re-open closed Jira tickets, fix did not hold")
        if self.toil_pct > 30:
            flags.append(f"Toil at {self.toil_pct:.0f}% of capacity (target: <20%): automate this sprint")
        return flags

from dataclasses import dataclass
from typing import List, Optional
from datetime import date
from enum import Enum

class RiskLevel(Enum):
    CRITICAL = "P1"   # could cause P1 incident without notice
    HIGH     = "P2"
    MEDIUM   = "P3"

@dataclass
class ReliabilityRisk:
    risk_id: str
    description: str
    risk_level: RiskLevel
    likelihood: str         # "imminent", "likely", "possible"
    impact: str             # "P1 outage", "SLO miss", "data leak"
    owner: str
    due_date: date
    status: str             # "open", "in_progress", "mitigated", "accepted"
    mitigation_plan: str
    linked_jira: str = ""

    @property
    def is_stale(self) -> bool:
        return (
            self.status in ("open", "in_progress")
            and (date.today() - self.due_date).days > 7
        )

    def register_line(self) -> str:
        stale_flag = " [STALE - ESCALATE]" if self.is_stale else ""
        return (
            f"[{self.risk_level.value}][{self.status}] {self.risk_id}: "
            f"{self.description}{stale_flag}\n"
            f"  Likelihood: {self.likelihood} | Impact: {self.impact}\n"
            f"  Owner: {self.owner} | Due: {self.due_date} | {self.linked_jira}"
        )


def update_risk_register(
    risks: List[ReliabilityRisk],
    new_risks: List[ReliabilityRisk],
    resolved_ids: List[str],
) -> List[ReliabilityRisk]:
    updated = [r for r in risks if r.risk_id not in resolved_ids]
    updated.extend(new_risks)
    stale = [r for r in updated if r.is_stale]
    if stale:
        print(f"[risk] {len(stale)} stale items need EM escalation:")
        for r in stale:
            print(f"  {r.risk_id}: {r.description}")
    return sorted(updated, key=lambda r: (r.risk_level.value, r.due_date))
